CREATE TABLE ANALYTICS.FACT_DIAGNOSIS
(
 DIAGNOSIS_FACT_KEY        number(38,0) NOT NULL COMMENT 'Surrogate key for diagnosis fact row',
 ENCOUNTER_KEY             number(38,0) COMMENT 'Encounter surrogate key reference value (no FK constraint)',
 PATIENT_KEY               number(38,0) NOT NULL COMMENT 'Link to patient dimension',
 DIAGNOSIS_CODE            varchar(20) NOT NULL COMMENT 'Diagnosis code assigned to the patient',
 DIAGNOSIS_DATE_KEY        number(8,0) COMMENT 'Date key when diagnosis was recorded',
 DIAGNOSIS_SEQUENCE        number(3,0) COMMENT 'Sequence number, for example 1 = primary diagnosis',
