 CREATED_TIMESTAMP         timestamp NOT NULL,
 CREATED_BY_NAME           varchar(50) NOT NULL,
 UPDATED_TIMESTAMP         timestamp NOT NULL,
 UPDATED_BY_NAME           varchar(50) NOT NULL,

 CONSTRAINT pk_FACT_DIAGNOSIS PRIMARY KEY ( DIAGNOSIS_FACT_KEY ),
 CONSTRAINT fk_FACT_DIAGNOSIS_DIM_DATE FOREIGN KEY ( DIAGNOSIS_DATE_KEY ) REFERENCES ANALYTICS.DIM_DATE ( DATE_KEY ),
 CONSTRAINT fk_FACT_DIAGNOSIS_DIM_PATIENT FOREIGN KEY ( PATIENT_KEY ) REFERENCES ANALYTICS.DIM_PATIENT ( PATIENT_KEY )
)
CLUSTER BY ( DIAGNOSIS_DATE_KEY, PATIENT_KEY )
COMMENT = 'Diagnosis fact table, one row per diagnosis per patient and encounter.';
